#include <bits/stdc++.h>
using namespace std;
int s,n,d,a[11],b[11],dp[1000006];
int main(){
    scanf("%d%d%d",&s,&n,&d);
    for(int i=1;i<=d;i++)
        scanf("%d%d",&a[i],&b[i]);
    for(int y=1;y<=n;y++){
        memset(dp,0,sizeof(dp));
        for(int i=1;i<=d;i++)
            for(int j=a[i]/1000;j<=s/1000;j++)
                dp[j]=max(dp[j],dp[j-a[i]/1000]+b[i]);
        s+=dp[s/1000];
    }
    printf("%d",s);
    return 0;
}
